  // Social Engagement
  'What is engagement rate on social media?': { prompt: 'Qu\'est-ce que le taux d\'engagement sur les réseaux sociaux ?', options: ['Les heures passées en ligne', 'Le pourcentage de votre audience qui interagit avec votre contenu (likes, commentaires, partages)', 'Le nombre de publications', 'Le nombre d\'abonnés'], correctAnswer: 'Le pourcentage de votre audience qui interagit avec votre contenu (likes, commentaires, partages)' },
  'Engagement rate is a more important metric than follower count for business success.': { prompt: 'Le taux d\'engagement est une métrique plus importante que le nombre d\'abonnés pour le succès commercial.', options: ['Vrai', 'Faux'], correctAnswer: 'Vrai' },
