  // Email Performance
  'What is a good email open rate?': { prompt: 'Qu\'est-ce qu\'un bon taux d\'ouverture de courriel ?', options: ['100 %', '20-30 % selon l\'industrie', '1 %', '90 %'], correctAnswer: '20-30 % selon l\'industrie' },
  'The subject line is the biggest factor affecting email open rates.': { prompt: 'L\'objet du courriel est le facteur le plus important affectant les taux d\'ouverture.', options: ['Vrai', 'Faux'], correctAnswer: 'Vrai' },
  'Click-through rate measures the percentage of email recipients who ___ on a link.': { prompt: 'Le taux de clic mesure le pourcentage de destinataires de courriels qui ___ sur un lien.', options: ['Cliquent', 'Survolent', 'Ignorent', 'Suppriment'], correctAnswer: 'Cliquent' },
  'How can you improve email deliverability?': { prompt: 'Comment améliorer la délivrabilité des courriels ?', options: ['Envoyer depuis un compte Gmail gratuit', 'Envoyer à tout le monde possible', 'Utiliser des majuscules dans les objets', 'Authentifier votre domaine (SPF, DKIM, DMARC), nettoyer votre liste et éviter les déclencheurs de spam'], correctAnswer: 'Authentifier votre domaine (SPF, DKIM, DMARC), nettoyer votre liste et éviter les déclencheurs de spam' },
  'A/B testing subject lines helps optimize open rates over time.': { prompt: 'Tester les objets en A/B aide à optimiser les taux d\'ouverture au fil du temps.', options: ['Vrai', 'Faux'], correctAnswer: 'Vrai' },
  'What causes emails to land in spam?': { prompt: 'Qu\'est-ce qui fait atterrir les courriels dans le spam ?', options: ['Avoir du bon contenu', 'Utiliser un formatage approprié', 'Des objets de spam, pas d\'authentification, des taux de plainte élevés ou des listes achetées', 'Envoyer trop peu de courriels'], correctAnswer: 'Des objets de spam, pas d\'authentification, des taux de plainte élevés ou des listes achetées' },
  'Regularly removing inactive subscribers improves your overall email ___ rate.': { prompt: 'Supprimer régulièrement les abonnés inactifs améliore votre taux d\'___ courriel global.', options: ['Engagement', 'Coût', 'Envoi', 'Plainte'], correctAnswer: 'Engagement' },
  'Personalized emails (using the subscriber\'s name and relevant content) perform better than generic blasts.': { prompt: 'Les courriels personnalisés (utilisant le nom de l\'abonné et du contenu pertinent) performent mieux que les envois génériques.', options: ['Vrai', 'Faux'], correctAnswer: 'Vrai' },

  // Cash Flow & Planning
  'What is cash flow?': { prompt: 'Qu\'est-ce que le flux de trésorerie ?', options: ['Votre revenu total', 'Combien d\'argent vous avez dans votre portefeuille', 'Votre marge bénéficiaire', 'Le mouvement d\'argent entrant et sortant de votre entreprise sur une période'], correctAnswer: 'Le mouvement d\'argent entrant et sortant de votre entreprise sur une période' },
  'A profitable business can still fail due to poor cash flow management.': { prompt: 'Une entreprise rentable peut quand même échouer à cause d\'une mauvaise gestion du flux de trésorerie.', options: ['Vrai', 'Faux'], correctAnswer: 'Vrai' },
  'Cash flow ___ means you have more money going out than coming in.': { prompt: 'Un flux de trésorerie ___ signifie que vous avez plus d\'argent qui sort que qui entre.', options: ['Négatif', 'Positif', 'Neutre', 'Zéro'], correctAnswer: 'Négatif' },
  'What is the #1 reason small businesses fail?': { prompt: 'Quelle est la raison #1 de l\'échec des petites entreprises ?', options: ['Trop de profit', 'Manquer de liquidités', 'De mauvais produits', 'Trop de clients'], correctAnswer: 'Manquer de liquidités' },
  'Revenue and cash flow are the same thing.': { prompt: 'Le revenu et le flux de trésorerie sont la même chose.', options: ['Vrai', 'Faux'], correctAnswer: 'Faux' },
  'How many months of expenses should an online business keep as reserve?': { prompt: 'Combien de mois de dépenses une entreprise en ligne devrait-elle garder en réserve ?', options: ['Seulement 1 semaine', '0 — tout dépenser', '3 à 6 mois de dépenses d\'exploitation', '10 ans'], correctAnswer: '3 à 6 mois de dépenses d\'exploitation' },
  'A cash flow ___ projects your expected income and expenses over the coming months.': { prompt: 'Une ___ de flux de trésorerie projette vos revenus et dépenses prévus sur les mois à venir.', options: ['Prévision', 'Rêve', 'Souhait', 'Espérance'], correctAnswer: 'Prévision' },
  'Tracking every business expense is unnecessary if your revenue is growing.': { prompt: 'Suivre chaque dépense d\'entreprise est inutile si vos revenus augmentent.', options: ['Vrai', 'Faux'], correctAnswer: 'Faux' },

  // Profit Margins
  'What is a profit margin?': { prompt: 'Qu\'est-ce qu\'une marge bénéficiaire ?', options: ['Le montant que vous investissez', 'Le revenu total', 'Le pourcentage du revenu qui reste comme profit après tous les coûts', 'Les ventes brutes'], correctAnswer: 'Le pourcentage du revenu qui reste comme profit après tous les coûts' },
  'A business with $1M revenue and 5% profit margin makes $50,000 in profit.': { prompt: 'Une entreprise avec 1 M$ de revenus et 5 % de marge bénéficiaire fait 50 000 $ de profit.', options: ['Vrai', 'Faux'], correctAnswer: 'Vrai' },
  'Gross margin is revenue minus the cost of ___ sold (COGS).': { prompt: 'La marge brute est le revenu moins le coût des ___ vendues (COGS).', options: ['Marchandises', 'Obtentions', 'Croissances', 'Sorties'], correctAnswer: 'Marchandises' },
  'What is the difference between gross and net profit margin?': { prompt: 'Quelle est la différence entre la marge bénéficiaire brute et nette ?', options: ['Elles sont identiques', 'La marge brute inclut les impôts', 'La marge nette est toujours plus élevée', 'La marge brute exclut les dépenses d\'exploitation ; la marge nette inclut toutes les dépenses'], correctAnswer: 'La marge brute exclut les dépenses d\'exploitation ; la marge nette inclut toutes les dépenses' },
  'Digital products (courses, software) typically have higher profit margins than physical products.': { prompt: 'Les produits numériques (cours, logiciels) ont généralement des marges bénéficiaires plus élevées que les produits physiques.', options: ['Vrai', 'Faux'], correctAnswer: 'Vrai' },
  'How can you improve profit margins?': { prompt: 'Comment améliorer les marges bénéficiaires ?', options: ['Baisser tous les prix', 'Augmenter uniquement les revenus', 'Réduire les coûts, augmenter les prix, améliorer l\'efficacité et vendre des produits à marge plus élevée', 'Ignorer les dépenses'], correctAnswer: 'Réduire les coûts, augmenter les prix, améliorer l\'efficacité et vendre des produits à marge plus élevée' },
  'A healthy e-commerce net profit margin is typically ___% or above.': { prompt: 'Une marge bénéficiaire nette e-commerce saine est généralement de ___% ou plus.', options: ['10', '1', '50', '0'], correctAnswer: '10' },
  'Revenue growth without profit growth is sustainable long-term.': { prompt: 'La croissance des revenus sans croissance des profits est durable à long terme.', options: ['Vrai', 'Faux'], correctAnswer: 'Faux' },

  // Business Structure
  'What is the simplest business structure?': { prompt: 'Quelle est la structure d\'entreprise la plus simple ?', options: ['S-Corp', 'L\'entreprise individuelle', 'LLC', 'Corporation'], correctAnswer: 'L\'entreprise individuelle' },
